"use strict";
var SqlScan = require('../lib/app-sqlscan');
var connect = require('connect');
var test = require('supertest');
var expect = require('expect.js');


var sqlscan = SqlScan({ 
  prefix: 'restful-store.daily.tbsite.net:3800', 
  appkey: '51fb509427789'
});
var prefix = '/r/sqlscans';

var app = connect();
app.use(connect.cookieParser());
app.use(prefix, sqlscan.middleware());
app.use(function (req, res, next) {
  res.statusCode = 200;
  res.end('next');
});

var successfetch = function (err, data, cb) {
  process.nextTick(function () {
    cb(err, data);
  });
};

describe('sqlscan rest api server', function () {
  var _upload = sqlscan.client.upload;
  before(function (done) {
    app.listen(0, done);
  });

  after(function () {
    sqlscan.client.upload = _upload;
  });

  it('/upload/get should be ok', function (done) {
    sqlscan.client.upload = function(buffer, name, cb){
      var rtn = {name:'get', size:buffer.length};
      successfetch(null, rtn, cb);
    };
    test(app)
    .get(prefix + '/upload/testget')
    .expect(200)
    .expect('{"returnCode":"0","returnValue":{"name":"get","size":13}}')
    .end(function (err, res) {
      expect(err).to.be(null);
      done();
    });
  });

  it('/upload/get fileContents error', function (done) {
    test(app)
    .get(prefix + '/upload')
    .expect(200)
    .expect('{"returnCode":"1","returnMessage":"url error， fileContents needed"}')
    .end(function (err, res) {
      expect(err).to.be(null);
      done();
    });
  });

  it('/upload/get tfs error', function (done) {
    sqlscan.client.upload = function(buffer, name, cb){
      successfetch('tfs error', '', cb);
    };
    test(app)
    .get(prefix + '/upload/testget')
    .expect(500)
    .expect('{"returnCode":"1","returnMessage":"tfs error"}')
    .end(function (err, res) {
      expect(err).to.be(null);
      done();
    });
  });

  it('/upload/post should be ok', function (done) {
    sqlscan.client.upload = function(buffer, name, cb){
      var rtn = {name:'post', size:buffer.length};
      successfetch(null, rtn, cb);
    };
    test(app)
    .post(prefix + '/upload/testpost')
    .expect(200)
    .expect('{"returnCode":"0","returnValue":{"name":"post","size":0}}')
    .end(function (err, res) {
      expect(err).to.be(null);
      done();
    });
  });

  it('/notFound', function (done) {
    test(app)
    .get(prefix + '/notFound')
    .expect(404)
    .end(function (err, res) {
      expect(err).to.be(null);
      done();
    });
  });
});



